const contactResp = $('GHL Get Contact').item.json;
const contact = contactResp.contact || contactResp;

// 1. DÜZELTME: Veriyi doğrudan root'tan değil, webhook'un 'body' kısmından alıyoruz.
const webhook = $('Webhook Incoming').item.json.body || $('Webhook Incoming').item.json;

const tags = contact.tags || [];
if (tags.includes('human_handoff') || tags.includes('urgent_handoff')) {
  return [{ json: { action: 'STOP_HUMAN', reason: 'human_handoff tag' } }];
}
if (contact.assignedTo && contact.assignedTo !== '') {
  return [{ json: { action: 'STOP_HUMAN', reason: 'assigned to user' } }];
}

// 2. DÜZELTME: GHL'den gelen JSON string formatındaki karmaşık mesajı temiz metne çeviriyoruz.
let cleanMessage = webhook.mergedMessage || '';
try {
    const parsed = JSON.parse(cleanMessage);
    if (parsed.body) {
        cleanMessage = parsed.body;
    }
} catch(e) {
    // Zaten düz metinse olduğu gibi kalır
}

return [{ json: {
  action: 'CONTINUE',
  contactId: webhook.contactId,
  contactName: contact.name || contact.firstName || 'Hasta',
  contactPhone: contact.phone || '',
  contactEmail: contact.email || '',
  clinicId: webhook.clinicId || $('Config').item.json.clinicId,
  mergedMessage: cleanMessage, 
  containsImage: webhook.containsImage || false,
  imageCount: webhook.imageCount || 0,
  imageUrl: webhook.imageUrl || null
} }];

const result = $input.item.json;
const conversations = Array.isArray(result) ? result : [result];
const prev = $('Human Check').item.json;

if (conversations.length > 0 && conversations[0] && conversations[0].id) {
  const c = conversations[0];
  return [{ json: {
    ...prev, conversationExists: true,
    conversationId: c.id,
    currentStage: c.current_stage || 'GREETING',
    collectedData: c.collected_data || {},
    leadSignals: c.lead_signals || {},
    currentScore: c.lead_score || 0,
    humanTakeover: c.human_takeover || false,
    imagesReceived: c.images_received || 0,
    messageCount: c.message_count || 0
  } }];
}
return [{ json: {
  ...prev, conversationExists: false,
  conversationId: null, currentStage: 'GREETING',
  collectedData: {}, leadSignals: {},
  currentScore: 0, humanTakeover: false,
  imagesReceived: 0, messageCount: 0
} }];

const prev = $('Check Conversation').item.json;
const created = $input.item.json;
const arr = Array.isArray(created) ? created : [created];
return [{ json: { ...prev, conversationId: arr[0]?.id, conversationExists: true } }];

const checkData = $('Check Conversation').item.json;

if (checkData.conversationExists === false) {
  return [{ json: $('Set New Conv ID').item.json }];
} else {
  return [{ json: checkData }];
}

const convData = $('Get Conv Data').first().json;
const clinicArr = $('Get Clinic').first().json;
const clinic = Array.isArray(clinicArr) ? clinicArr[0] : clinicArr;
const servicesArr = $('Get Services').first().json;
const services = Array.isArray(servicesArr) ? servicesArr : [servicesArr];
const faqsArr = $('Get FAQs').first().json;
const faqs = Array.isArray(faqsArr) ? faqsArr : [faqsArr];
const historyArr = $('Get History').first().json;
const history = Array.isArray(historyArr) ? historyArr : (historyArr && historyArr.id ? [historyArr] : []);

// === FULL services text for reply stage ===
const servicesText = services
  .filter(s => s && s.display_name)
  .map(s => `\nHİZMET: ${s.display_name} (${s.category || ''})
Açıklama: ${s.description_for_ai || ''}
Süre: ${s.procedure_duration || 'Belirtilmemiş'}
Anestezi: ${s.anesthesia_type || 'Belirtilmemiş'}
İyileşme: ${s.recovery_time || 'Belirtilmemiş'}
Tam Sonuç: ${s.final_result_time || 'Belirtilmemiş'}
Hastanede Kalış: ${s.hospital_stay || 'Belirtilmemiş'}
Hasta Endişeleri: ${(s.common_patient_concerns || []).join(', ')}
Fiyat Sorusuna Yanıt: ${s.pricing_response || 'Kişiye özel belirlenir'}
Söyleyebileceklerin: ${(s.what_ai_can_say || []).join(', ')}
ASLA Söyleme: ${(s.what_ai_must_not_say || []).join(', ')}
İtiraz Yanıtları: ${JSON.stringify(s.objections || {})}`)
  .join('\n---\n');

// === SHORT services list for analysis stage ===
const servicesShort = services
  .filter(s => s && s.display_name)
  .map(s => `${s.service_key}: ${s.display_name} (${s.category || ''})`)
  .join('\n');

const faqsText = faqs
  .filter(f => f && f.answer)
  .map(f => `Tetikleyiciler: [${(f.question_patterns || []).join(', ')}] → Yanıt: ${f.answer}`)
  .join('\n');

let isMedicalImage = false;
try { isMedicalImage = $('Parse Vision Result').first().json.isMedicalImage || false; } catch(e) {}
let imageNote = '';
if (convData.containsImage) {
  if (isMedicalImage) {
    imageNote = `\n[SİSTEM NOTU: Hasta TIBBİ bir görsel gönderdi. Bu çok önemli bir hot lead! Hastaya uzmanımızın en kısa sürede kendisini arayacağını sıcak ve empatik bir şekilde belirt. Görseli analiz etme, sadece alındığını ve uzmanın inceleyeceğini söyle.]`;
  } else {
    imageNote = `\n[SİSTEM NOTU: Hasta bu mesajla birlikte ${convData.imageCount} adet görsel gönderdi. Empatik karşıla, doktorun ön görüşmede değerlendireceğini belirt. Görseli analiz etme.]`;
  }
}

// ══════════════════════════════════════
// STAGE 1: ANALYSIS SYSTEM PROMPT
// ══════════════════════════════════════
const analysisSystemPrompt = `Sen bir klinik konuşma analiz motorusun. Hasta mesajını analiz edip yapılandırılmış veri çıkar.

## KLİNİK
Ad: ${clinic.name}
Tür: ${clinic.clinic_type}

## HİZMETLER
${servicesShort}

## MEVCUT DURUM
Aşama: ${convData.currentStage}
ÖNCEKİ TOPLANAN VERİLER (BUNLARI ASLA SİLME!): ${JSON.stringify(convData.collectedData)}
Sinyaller: ${JSON.stringify(convData.leadSignals)}

## SİNYAL SINIFLANDIRMA KURALLARI (ÇOK ÖNEMLİ)
- Eğer hasta mesajında: "acil", "hemen", "bugün", "en kısa sürede", "acele", "urgent" gibi ifadeler varsa:
  → lead_signals.urgency = "high"
- Eğer hasta "yakında", "bu hafta", "önümüzdeki günler", "kısa zamanda" gibi ifadeler kullanıyorsa:
  → lead_signals.urgency = "medium"
- Eğer zaman belirtmiyorsa:
  → lead_signals.urgency = "low" veya "unknown"

- Eğer hasta açıkça randevu istiyorsa, gün/saat soruyorsa, "gelmek istiyorum", "ön görüşme istiyorum" diyorsa:
  → lead_signals.buying_intent = "ready"
- Eğer sadece bilgi alıyorsa:
  → lead_signals.buying_intent = "considering"
- Eğer sadece bakınıyorsa:
  → lead_signals.buying_intent = "just_browsing"

- Eğer hasta kısa, tek kelimelik cevaplar veriyorsa:
  → lead_signals.engagement_level = "low"
- Eğer detaylı anlatıyorsa, soru soruyorsa:
  → lead_signals.engagement_level = "high"
- Aksi halde:
  → lead_signals.engagement_level = "medium"

- Eğer hasta fiyat, ücret, ödeme, taksit, bütçe gibi konuları soruyorsa:
  → collected_data.budget_awareness = "fiyat_sordu" veya "butce_belirti"

- collected_data.timeline için MUTLAKA şu enum değerlerden birini seç:
  * "hemen" → hasta acil, bugün, en kısa sürede istiyor
  * "1_hafta" → bu hafta, haftaya, önümüzdeki hafta gibi ifadeler
  * "1_ay" → bu ay, yakında, 1-2 ay içinde
  * "3_ay" → 3 ay sonra, ileride, düşünüyorum
  * "belirsiz" → zaman belirtmedi veya belirsiz
  ASLA serbest metin yazma, SADECE bu 5 enum değerden birini kullan!

- collected_data.preferred_day_time: Hasta görüşme/randevu için spesifik gün veya saat belirtirse buraya yaz (örn: "haftaya salı 15:00", "Cuma sabahı"). Genel timeline ile karıştırma.

- handoff_recommended: Şu durumlarda MUTLAKA true yap:
  * Hasta açıkça randevu veya ön görüşme talep etti
  * Hasta spesifik gün/saat verdi
  * buying_intent = "ready" ise
  * Hasta "gelebilirim", "hazırım", "ne zaman müsaitsiniz" gibi net sinyal verdi

## GÖREV
SADECE aşağıdaki JSON formatında yanıt ver:
{
  "metadata": {
    "current_stage": "GREETING|DISCOVERY|TRUST_BUILDING|APPOINTMENT_OFFER|INFO_COLLECTION|CLOSING|NURTURING",
    "collected_data": {
      "name": null, "interested_service": null, "interested_service_key": null,
      "pain_point": null, "pain_point_duration": null,
      "timeline": null, "previous_consultation": null, "previous_procedure": null,
      "budget_awareness": "not_asked", "referral_source": null,
      "special_health_notes": null, "preferred_consultation_type": null,
      "preferred_day_time": null
    },
    "lead_signals": {
      "urgency": "unknown", "engagement_level": "unknown",
      "buying_intent": "unknown", "objections_raised": [], "objections_resolved": []
    },
    "handoff_recommended": false,
    "handoff_reason": null
  },
  "reply_guidance": "Yanıt asistanı için 1-2 cümlelik yönlendirme"
}

ÇOK ÖNEMLİ KURAL: JSON çıktısı üretirken 'ÖNCEKİ TOPLANAN VERİLER' içindeki dolu olan verileri ASLA null yapma! 
Sadece yeni mesajda yeni bir bilgi varsa üzerine ekle. 
Eğer hasta sadece "randevu istiyorum" diyorsa, önceki hizmeti hafızanda tut ve current_stage'i APPOINTMENT_OFFER yap.`;

// ══════════════════════════════════════
// STAGE 2: REPLY SYSTEM PROMPT (base)
// ══════════════════════════════════════
const replySystemPrompt = `Sen ${clinic.name} kliniğinin WhatsApp asistanısın. Hastaları karşılıyor, bilgilendiriyor ve ön görüşme randevusuna yönlendiriyorsun.

## KLİNİK PROFİLİ
Ad: ${clinic.name}
Tür: ${clinic.clinic_type}
Adres: ${clinic.address}, ${clinic.district}, ${clinic.city}
Telefon: ${clinic.phone}
Çalışma Saatleri: ${JSON.stringify(clinic.working_hours)}
Otopark: ${clinic.parking_info || 'Bilgi yok'}
Baş Doktor: ${clinic.lead_doctor_name}, ${clinic.lead_doctor_title}

## HİZMETLER
${servicesText}

## SIK SORULAN SORULAR
${faqsText}

## KONUŞMA KURALLARI
1. Her mesajda SADECE 1 soru sor.
2. Yanıtların 2-4 cümle olsun ancak bilgi vermekten kaçınma. Robotik konuşma.
3. KESİNLİKLE her mesajda "Merhaba" veya "Hoş geldiniz" DEME. Sadece ilk mesajda selam ver.
4. HAFIZANI KULLAN: Konuşma geçmişinde hastanın ilgilendiği işlem zaten belli olduysa, randevu istediğinde ASLA "Hangi işlemle ilgileniyorsunuz?" diye TEKRAR SORMA. Doğrudan o işlem için gün ve saat sor.
5. Asla tıbbi teşhis koyma, garanti verme.
6. Rakip klinik kötüleme.
7. Fiyat sorulursa kişiye özel olduğunu belirt, ön görüşmeye yönlendir.`;

// === Build conversation history for reuse ===
const historyMessages = [];
for (const msg of history) {
  if (msg && msg.content) {
    historyMessages.push({ role: msg.role === 'assistant' ? 'assistant' : 'user', content: msg.content });
  }
}

// === Stage 1 messages ===
const analysisMessages = [
  { role: 'system', content: analysisSystemPrompt },
  ...historyMessages,
  { role: 'user', content: convData.mergedMessage + imageNote }
];

return [{
  json: {
    analysisMessages,
    replySystemPrompt,
    historyMessages,
    userMessage: convData.mergedMessage,
    imageNote,
    conversationId: convData.conversationId,
    contactId: convData.contactId,
    clinicId: convData.clinicId,
    containsImage: convData.containsImage,
    imageCount: convData.imageCount,
    currentScore: convData.currentScore,
    imagesReceived: convData.imagesReceived,
    messageCount: convData.messageCount,
    contactName: convData.contactName
  }
}];

const aiResponse = $input.item.json;
let metadata = {}, replyGuidance = '';

try {
  const raw = aiResponse.choices[0].message.content;
  const parsed = JSON.parse(raw);
  metadata = parsed.metadata || {};
  replyGuidance = parsed.reply_guidance || '';
} catch (e) {
  metadata = {
    current_stage: 'GREETING',
    collected_data: {},
    lead_signals: {},
    handoff_recommended: false,
    handoff_reason: null
  };
  replyGuidance = 'Hastayı sıcak karşıla.';
}

return [{ json: {
  metadata,
  replyGuidance,
  analysisTokens: aiResponse.usage?.total_tokens || 0
} }];

const analysis = $('Parse Analysis').item.json;
const promptData = $('Build AI Prompt').item.json;

const analysisContext = `\n\n## ANALİZ SONUÇLARI (İç kullanım - hastaya gösterme)\nMevcut Aşama: ${analysis.metadata.current_stage}\nToplanan Veriler: ${JSON.stringify(analysis.metadata.collected_data)}\nLead Sinyalleri: ${JSON.stringify(analysis.metadata.lead_signals)}\nYönlendirme: ${analysis.replyGuidance}${analysis.metadata.handoff_recommended ? '\nNOT: Bu hasta satış ekibine yönlendirilecek. Nazikçe bilgilendirmeye devam et.' : ''}\n\n## GÖREV\nYukarıdaki analiz sonuçlarına ve konuşma geçmişine dayanarak hastaya doğal, empatik bir WhatsApp mesajı yaz.\nSADECE mesaj metnini yaz. JSON veya başka format KULLANMA. Markdown KULLANMA.`;

const replyMessages = [
  { role: 'system', content: promptData.replySystemPrompt + analysisContext },
  ...promptData.historyMessages,
  { role: 'user', content: promptData.userMessage + promptData.imageNote }
];

return [{ json: { replyMessages } }];

const replyResponse = $input.item.json;
const analysis = $('Parse Analysis').item.json;
const promptData = $('Build AI Prompt').item.json;
let reply = '';

try {
  reply = replyResponse.choices[0].message.content || '';
  reply = reply.replace(/^```[\s\S]*?```$/gm, '').trim();
  if (reply.startsWith('{')) {
    try {
      const p = JSON.parse(reply);
      reply = p.reply || p.message || p.text || reply;
    } catch(e) {}
  }
  if (reply.startsWith('"') && reply.endsWith('"')) {
    reply = reply.slice(1, -1);
  }
  reply = reply.trim();
} catch (e) {
  reply = 'Mesajınız için teşekkür ederim. Size nasıl yardımcı olabilirim?';
}

if (!reply) reply = 'Mesajınız için teşekkür ederim. Size nasıl yardımcı olabilirim?';

const metadata = analysis.metadata || {};
const cd = metadata.collected_data || {};
const ls = metadata.lead_signals || {};
let score = 0, breakdown = {};

if (cd.interested_service) { score += 10; breakdown.service = 10; }
if (cd.pain_point && cd.pain_point.length > 20) { score += 10; breakdown.pain_detailed = 10; }
else if (cd.pain_point) { score += 5; breakdown.pain_basic = 5; }

const tScores = { 'hemen': 20, '1_hafta': 15, '1_ay': 8, '3_ay': 3, 'belirsiz': 0 };
if (cd.timeline) {
  const ts = tScores[cd.timeline] !== undefined ? tScores[cd.timeline] : 15;
  score += ts; breakdown.timeline = ts;
}
if (cd.previous_consultation === 'baska_klinik') { score += 10; breakdown.researched = 10; }
if (cd.previous_consultation === 'ameliyat_olmus') { score += 12; breakdown.revision = 12; }
if (['fiyat_sordu','taksit_sordu','butce_belirti'].includes(cd.budget_awareness)) { score += 8; breakdown.budget = 8; }
if (cd.preferred_consultation_type) { score += 10; breakdown.consult_pref = 10; }
if (cd.preferred_day_time || (cd.timeline && tScores[cd.timeline] === undefined)) { score += 15; breakdown.appt_interest = 15; }
if (ls.engagement_level === 'high') { score += 8; breakdown.high_eng = 8; }
else if (ls.engagement_level === 'medium') { score += 4; breakdown.med_eng = 4; }
if (ls.buying_intent === 'ready') { score += 15; breakdown.ready = 15; }
else if (ls.buying_intent === 'considering') { score += 8; breakdown.considering = 8; }
if (ls.urgency === 'high') { score += 7; breakdown.urgency = 7; }
if (ls.buying_intent === 'just_browsing') { score -= 5; breakdown.browsing = -5; }

const totalImages = (promptData.imagesReceived || 0) + (promptData.imageCount || 0);
if (totalImages > 0) { const s = Math.min(totalImages * 15, 30); score += s; breakdown.images = s; }
score = Math.max(0, Math.min(100, score));
let isMedicalImage = false;
try { isMedicalImage = $('Parse Vision Result').first().json.isMedicalImage || false; } catch(e) {}
if (isMedicalImage) { score = 85; breakdown = { medical_image: 85 }; }

const totalTokens = (analysis.analysisTokens || 0) + (replyResponse.usage?.total_tokens || 0);

return [{ json: {
  reply, metadata, score, breakdown,
  handoffNeeded: metadata.handoff_recommended === true || score >= 70,
  conversationId: promptData.conversationId,
  contactId: promptData.contactId,
  clinicId: promptData.clinicId,
  containsImage: promptData.containsImage,
  imageCount: promptData.imageCount,
  totalImages, messageCount: promptData.messageCount + 1,
  contactName: promptData.contactName,
  tokensUsed: totalTokens
} }];

