const visionResponse = $input.item.json;
const humanCheck = $('Human Check').item.json;
let isMedicalImage = false;
try {
  const content = (visionResponse.choices && visionResponse.choices[0].message.content) || '';
  const upper = content.trim().toUpperCase();
  isMedicalImage = upper.includes('TIBBI') && !upper.includes('TIBBI_DEGIL');
} catch(e) {
  isMedicalImage = false;
}
return [{ json: { ...humanCheck, isMedicalImage } }];

